---@class LFightRoundData
local LFightRoundData = classX("LFightRoundData", nil)
function LFightRoundData:ctor()
    ---@type number 第几回合
    self.round = 0
    ---@type LBattleHeroSpeedData[] 回合初始时英雄速度集合
    self.speedList = {}
    ---@type table<number, LFightBoutData>
    self.bouts = {}

    self.boutCount = 0
end

function LFightRoundData:ToJsonTable()
    local jsonTab = {}
    jsonTab.round = self.round
    jsonTab.speedList = {}
    for i, v in pairs(self.speedList) do
        table.insert(jsonTab.speedList, v:ToJsonTable())
    end
    jsonTab.bouts = {}
    for i, v in ipairs(self.bouts) do
        table.insert(jsonTab.bouts, v:ToJsonTable())
    end
    return jsonTab
end

function LFightRoundData:InitData(fromData, lifeState)
    self.round = fromData.round
    self.bouts = {}

    self:SetRoundData(fromData, lifeState)
end
function LFightRoundData:SetRoundData(fromData, lifeState)
    self.speedList = {}

    local speedList = fromData.speedList
    local bouts = fromData.bouts
    self:AddSpeedList(speedList)
    self:AddBouts(bouts, lifeState)
end

function LFightRoundData:AddSpeedList(speedList)
    if not speedList then
        return
    end

    for i, v in ipairs(speedList) do
        local speedInfo = self:NewHeroSpeed(v)
        table.insert(self.speedList, speedInfo)
    end
end

function LFightRoundData:NewHeroSpeed(v)
    local speedInfo = LBattleHeroSpeedData:new(v)
    return speedInfo
end

function LFightRoundData:AddBouts(bouts, lifeState)
    if not bouts then
        return
    end
    for i, v in ipairs(bouts) do
        ---@type LFightBoutData
        local bout = LFightBoutData:new()
        bout:InitData(v, lifeState)
        table.insert(self.bouts, bout)
    end

    self.boutCount = #self.bouts
end

function LFightRoundData:GetBout(boutIdx)
    return self.bouts[boutIdx]
end
function LFightRoundData:GetBoutCount()
    return self.boutCount
end

function LFightRoundData:HasBout(boutIdx)
    return (self.bouts[boutIdx] ~= nil)
end

function LFightRoundData:GetSpeedList()
    return self.speedList
end

return LFightRoundData